import{_ as e,o as a,c as r,al as i}from"./chunks/framework.Dmfvx4Xt.js";const p=JSON.parse('{"title":"Interface overview","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/probprog/interface-overview.md","filePath":"tutorials/probprog/interface-overview.md","lastUpdated":null}'),d={name:"tutorials/probprog/interface-overview.md"};function o(n,t,s,l,c,g){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="probprog-interface-overview" tabindex="-1">Interface overview <a class="header-anchor" href="#probprog-interface-overview" aria-label="Permalink to &quot;Interface overview {#probprog-interface-overview}&quot;">​</a></h1><p>The public surface of <code>Reactant.ProbProg</code> is partitioned into four groups: modeling primitives, inference drivers, persistent state, and data types. The full signatures and semantics are documented in the <a href="/Reactant.jl/previews/PR2834/api/probprog#probprog-api">API reference</a>; the tables below are a quick index.</p><h2 id="Modeling-primitives" tabindex="-1">Modeling primitives <a class="header-anchor" href="#Modeling-primitives" aria-label="Permalink to &quot;Modeling primitives {#Modeling-primitives}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Signature</th><th style="text-align:right;">Role</th></tr></thead><tbody><tr><td style="text-align:right;"><a href="./@ref"><code>sample</code></a></td><td style="text-align:right;"><code>sample(rng, dist; symbol)</code> &amp;nbsp;/&amp;nbsp; <code>sample(rng, f, args...; symbol, logpdf, support, bounds)</code></td><td style="text-align:right;">Record a random choice from a distribution or user-defined sampler.</td></tr><tr><td style="text-align:right;"><a href="./@ref"><code>untraced_call</code></a></td><td style="text-align:right;"><code>untraced_call(rng, f, args...)</code></td><td style="text-align:right;">Execute a probabilistic function without recording its choices.</td></tr><tr><td style="text-align:right;"><a href="./@ref"><code>simulate</code></a> &amp;nbsp;/&amp;nbsp; <a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#simulate_"><code>simulate_</code></a></td><td style="text-align:right;"><code>simulate(rng, f, args...)</code></td><td style="text-align:right;">Forward-simulate a model; return its trace and prior log-density.</td></tr><tr><td style="text-align:right;"><a href="./@ref"><code>generate</code></a> &amp;nbsp;/&amp;nbsp; <a href="./@ref"><code>generate_</code></a></td><td style="text-align:right;"><code>generate(rng, constraint, f, args...)</code></td><td style="text-align:right;">Execute a model conditioned on observations; return the trace and log importance weight.</td></tr></tbody></table><h2 id="Inference" tabindex="-1">Inference <a class="header-anchor" href="#Inference" aria-label="Permalink to &quot;Inference {#Inference}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Signature</th><th style="text-align:right;">Role</th></tr></thead><tbody><tr><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/mcmc#mh"><code>mh</code></a></td><td style="text-align:right;"><code>mh(rng, trace, weight, f, args...; selection)</code></td><td style="text-align:right;">One Metropolis-Hastings step regenerating the selected addresses.</td></tr><tr><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/mcmc#mcmc"><code>mcmc</code></a></td><td style="text-align:right;"><code>mcmc(rng, trace, f, args...; selection, algorithm, num_samples, ...)</code></td><td style="text-align:right;">Trace-based HMC or NUTS.</td></tr><tr><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/mcmc#mcmc_logpdf"><code>mcmc_logpdf</code></a></td><td style="text-align:right;"><code>mcmc_logpdf(rng, logdensity_fn, initial_position, args...; algorithm, ...)</code></td><td style="text-align:right;">HMC or NUTS over a user-supplied log-density.</td></tr><tr><td style="text-align:right;"><a href="./@ref"><code>run_chain</code></a></td><td style="text-align:right;"><code>run_chain(rng, logpdf_fn, initial_position, args...; num_warmup, num_samples, chunk_size, ...)</code></td><td style="text-align:right;">Chunked chain driver with progress bar and resumable state.</td></tr></tbody></table><h2 id="State-and-persistence" tabindex="-1">State and persistence <a class="header-anchor" href="#State-and-persistence" aria-label="Permalink to &quot;State and persistence {#State-and-persistence}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Signature</th><th style="text-align:right;">Role</th></tr></thead><tbody><tr><td style="text-align:right;"><a href="./@ref"><code>MCMCState</code></a></td><td style="text-align:right;"><em>(struct)</em> <code>position, gradient, potential_energy, step_size, inverse_mass_matrix, rng</code></td><td style="text-align:right;">Resume token returned by every inference entry point.</td></tr><tr><td style="text-align:right;"><a href="./@ref"><code>save_state</code></a></td><td style="text-align:right;"><code>save_state(filename, state)</code></td><td style="text-align:right;">Serialise an <code>MCMCState</code> to disk.</td></tr><tr><td style="text-align:right;"><a href="./@ref"><code>load_state</code></a></td><td style="text-align:right;"><code>load_state(filename)</code></td><td style="text-align:right;">Reload an <code>MCMCState</code> from disk.</td></tr></tbody></table><h2 id="Data-types-and-distributions" tabindex="-1">Data types and distributions <a class="header-anchor" href="#Data-types-and-distributions" aria-label="Permalink to &quot;Data types and distributions {#Data-types-and-distributions}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Symbol</th><th style="text-align:right;">Role</th></tr></thead><tbody><tr><td style="text-align:right;"><a href="/Reactant.jl/previews/PR2834/tutorials/probprog/traces-and-inference#Trace"><code>Trace</code></a></td><td style="text-align:right;">Executed-model record: <code>choices</code>, <code>subtraces</code>, <code>retval</code>, <code>weight</code>.</td></tr><tr><td style="text-align:right;"><a href="./@ref"><code>Constraint</code></a></td><td style="text-align:right;">Dict-like <code>Address → value</code> mapping for observations.</td></tr><tr><td style="text-align:right;"><a href="./@ref"><code>Address</code></a></td><td style="text-align:right;">Immutable symbol path identifying a sample site.</td></tr><tr><td style="text-align:right;"><a href="./@ref"><code>Selection</code></a></td><td style="text-align:right;">Ordered set of addresses; constructed with <a href="./@ref"><code>select</code></a>.</td></tr><tr><td style="text-align:right;"><a href="./@ref"><code>Normal</code></a> &amp;nbsp;/&amp;nbsp; <a href="./@ref"><code>Exponential</code></a> &amp;nbsp;/&amp;nbsp; <a href="./@ref"><code>LogNormal</code></a> &amp;nbsp;/&amp;nbsp; <a href="./@ref"><code>Bernoulli</code></a></td><td style="text-align:right;">Built-in distributions, each carrying a static <code>shape::Tuple</code> and registered sampler / log-density.</td></tr></tbody></table>',10)])])}const m=e(d,[["render",o]]);export{p as __pageData,m as default};
